import { useState, useEffect } from 'react';
import { useNavigate, Link, NavLink } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

const api = axios.create({baseURL: 'http://localhost:5000'});


function Home() {
    const { user, isAuthenticated } = useAuth();

    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);
        setMessage('');

        try {
        const response = await api.post('/logout');

        if (response.status === 200) {
            setMessage('Вы успешно вышли из системы');
            setTimeout(() => {
            navigate('/login');
            }, 1000);
        }
        } catch (err) {
        setMessage('Ошибка при выходе из системы');
        console.error('Logout error:', err);
        } finally {
        setLoading(false);
        }
    };

    useEffect(() => {
        if (!isAuthenticated) {
        navigate('/login');
        }
    }, [isAuthenticated, navigate]);

    return(
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <Link className="navbar-brand fs-3 fw-bold">
                        <button 
                            onClick={handleLogout} 
                            className="logout-button"
                            disabled={loading}
                        >
                            {loading ? (
                            <>
                                <span className="spinner"></span>
                                Выход...
                            </>
                            ) : 'Выйти'}
                        </button>
                    {message && (
                    <div className="info-message">
                        {message}
                    </div>
                    )}
                    </Link>
                </div>
                <div className="container-fluid bg-dark py-2">
                    <div className="navbar-nav flex-row">
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/main" end> Главная </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads" end> Дороги </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/sings" end> Дорожные знаки </NavLink>
                        <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads/sings" end> Знаки на дорогах </NavLink>
                    </div>
                </div>
            </nav>
            <h1>Главная страница</h1>

        </div>
    );
}

export default Home;
